// Mapear y normalizar la estructura de respuesta estatal al esquema SQL
const items = input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  // Filtrar solo alertas críticas de huaicos o inundaciones en la Costa Norte/Centro
  if (data.region === 'Lambayeque' || data.region === 'Piura' || data.region === 'Ancash') {
    results.push({
      json: {
        tipo_evento: data.tipo || 'HUAICO',
        severidad: parseInt(data.nivel_peligro || '4'),
        // Construir WKT Polygon centrado en latitud/longitud del evento
        wkt_polygon: `POLYGON((` +
          `${data.longitude - 0.05} ${data.latitude - 0.05}, ` +
          `${data.longitude + 0.05} ${data.latitude - 0.05}, ` +
          `${data.longitude + 0.05} ${data.latitude + 0.05}, ` +
          `${data.longitude - 0.05} ${data.latitude + 0.05}, ` +
          `${data.longitude - 0.05} ${data.latitude - 0.05}` +
          `))`,
        detalles: JSON.stringify({
          institucion_emisora: data.entidad || 'INDICI/CENEPRED',
          boletin_nro: data.boletin || 'N/A',
          descripcion: data.descripcion || 'Amenaza detectada por monitoreo radar'
        })
      }
    });
  }
}

return results;
